set-variable.value:
#[%dw 2.0
output application/java

var customer = payload.payload[0]

var transactionString =
    (customer.TRANSACTIONS default "[]") as String

var transactions =
    if (isEmpty(transactionString))
        []
    else
        read(transactionString, "application/json")

var accountNumber =
    (customer.ACCOUNTNUMBER default "XXXXXXXXXX") as String

var accountHolder =
    (customer.FULLNAME default "N/A") as String

var balance =
    (customer.BALANCE default 0) as Number

var status =
    (customer.STATUS default "N/A") as String

var bankName =
    (customer.BANKNAME default "N/A") as String

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>

<style>

body{
font-family:'Segoe UI',Arial,sans-serif;
background:linear-gradient(135deg,#667eea,#764ba2);
padding:40px 20px;
}

.container{
max-width:1100px;
margin:auto;
background:white;
border-radius:20px;
overflow:hidden;
box-shadow:0 25px 50px rgba(0,0,0,.2);
}

.header{
background:linear-gradient(135deg,#1a237e,#283593);
color:white;
padding:40px;
text-align:center;
}

.bank-logo{
font-size:40px;
}

.header h1{
font-size:32px;
}

.account-info{
padding:30px;
}

.info-card{
display:grid;
grid-template-columns:repeat(4,1fr);
gap:20px;
background:#f8f9ff;
padding:25px;
border-radius:15px;
}

.label{
font-size:12px;
color:#666;
}

.value{
font-size:16px;
font-weight:bold;
color:#1a237e;
}


.summary{
padding:0 30px 30px;
display:grid;
grid-template-columns:repeat(3,1fr);
gap:20px;
}


.card{
padding:20px;
border:2px solid #eee;
border-radius:15px;
}


.card-icon{
font-size:30px;
}

.card-label{
color:#666;
font-size:13px;
}

.card-value{
font-size:22px;
font-weight:bold;
color:#1a237e;
}

.balance{
color:#4caf50;
}


.table-section{
padding:0 30px 40px;
}


table{
width:100%;
border-collapse:separate;
border-spacing:0 8px;
}


th{
background:#667eea;
color:white;
padding:15px;
}


td{
padding:15px;
text-align:center;
background:#fff;
border-bottom:1px solid #eee;
}


.badge{
padding:5px 12px;
border-radius:20px;
font-size:12px;
font-weight:bold;
}


.credit{
background:#e8f5e9;
color:#2e7d32;
}


.debit{
background:#ffebee;
color:#c62828;
}


.amount-credit{
color:#2e7d32;
font-weight:bold;
}


.amount-debit{
color:#c62828;
font-weight:bold;
}


.footer{
background:#f8f9ff;
padding:25px;
text-align:center;
}


</style>

</head>


<body>


<div class='container'>


<div class='header'>

<div class='bank-logo'>🏦 REAL BANK</div>

<h1>Transaction Statement</h1>

<p>Your financial overview at a glance</p>

</div>



<div class='account-info'>

<div class='info-card'>


<div>
<span class='label'>Account Number</span>
<br>
<span class='value'>" ++ accountNumber ++ "</span>
</div>



<div>
<span class='label'>Account Holder</span>
<br>
<span class='value'>" ++ accountHolder ++ "</span>
</div>



<div>
<span class='label'>Generated On</span>
<br>
<span class='value'>" ++ (now() as String) ++ "</span>
</div>

<div>
    <span class='label'>Status</span>
    <br/>
    <span class='value' style='color:" ++
        (if (upper(status) == "ACTIVE") "green" else "red")
        ++ ";'>
        ● " ++ status ++ "
    </span>
</div>


</div>

</div>




<div class='summary'>


<div class='card'>

<div class='card-icon'>💰</div>

<span class='card-label'>
Available Balance
</span>

<br>

<span class='card-value balance'>
₹ " ++ (balance as String) ++ "
</span>

</div>



<div class='card'>

<div class='card-icon'>📊</div>

<span class='card-label'>
Total Transactions
</span>

<br>

<span class='card-value'>
" ++ (sizeOf(transactions) as String) ++ "
</span>

</div>



<div class='card'>

<div class='card-icon'>🏛️</div>

<span class='card-label'>
Bank
</span>

<br>

<span class='card-value'>
REAL BANK
</span>

</div>


</div>




<div class='table-section'>


<table>


<tr>

<th>S.No</th>

<th>Transaction Type</th>

<th>Amount</th>

<th>Balance</th>

<th>Date & Time</th>

</tr>


" ++

(
transactions map ((item,index)->


"<tr>

<td>" ++ ((index+1) as String) ++ "</td>


<td>

<span class='badge " ++

(if ((item.transactionType default "") as String == "DEPOSIT")
"credit"
else
"debit")

++ "'>

" ++

((item.transactionType default "UNKNOWN") as String)

++

"</span>

</td>



<td class='" ++

(if ((item.transactionType default "") as String == "DEPOSIT")
"amount-credit"
else
"amount-debit")

++

"'>


" ++

(if ((item.transactionType default "") as String == "DEPOSIT")
"+"
else
"-")

++

"₹ "

++

((item.amount default 0) as String)

++

"</td>




<td>

₹ "

++

((item.balanceAfterTransaction default 0) as String)

++

"</td>



<td>

"

++

((item.timestamp default "") as String)

++

"

</td>


</tr>"

)

joinBy ""

)

++

"


</table>


</div>




<div class='footer'>

<b>Real Bank</b><br/><br/>

📞 Customer Care : +91 9494207062<br/>

✉ support@realbank.com<br/>

🌐 www.realbank.com<br/><br/>

© 2026 Real Bank. All Rights Reserved.<br/><br/>

This is an automated transaction alert. Please do not reply to this email.

</div>

</div>

</div>

</body>
</html>"]
